import ast
import inspect

# Parse checkpointer.py and analyze it
with open('src/checkpointer.py', 'r') as f:
    code = f.read()

tree = ast.parse(code)

# List all function definitions
print("=== Functions ===")
for node in ast.walk(tree):
    if isinstance(node, ast.FunctionDef):
        print(f"{node.name} @ line {node.lineno}")

# List all global assignments
print("\n=== Global variables ===")
for node in tree.body:
    if isinstance(node, ast.Assign):
        for target in node.targets:
            if isinstance(target, ast.Name):
                print(f"{target.id} @ line {node.lineno}")
    elif isinstance(node, ast.AnnAssign) and isinstance(node.target, ast.Name):
        print(f"{node.target.id} @ line {node.lineno}")

